// ─────────────────────────────────────────────────────────────────
// N8N CODE NODE — Newsletter Builder (Dual Trigger Safe)
// ─────────────────────────────────────────────────────────────────

// ── SAFE TRIGGER READER ───────────────────────────────────────
// N8n throws a hard Error (not null) when you access an unexecuted
// node. Optional chaining (?.) does NOT catch it. Use try/catch.

function safeGet(nodeName) {
  try {
    const item = $node[nodeName].json;  // throws if not executed
    if (!item) return null;
    return item;
  } catch (e) {
    return null;
  }
}

const gmailData = safeGet('Gmail Trigger');
const slackData = safeGet('Slack Trigger1');

// Determine active source
const isGmail = gmailData !== null;
const isSlack = slackData !== null;

// ── Extract topic ─────────────────────────────────────────────
// Gmail: use subject line as the topic, fallback to snippet
// Slack: use the message text, fallback to snippet
let topic = "AI Agents";
if (isGmail) {
  topic = gmailData.newsletter_content
       || gmailData.Subject
       || gmailData.snippet
       || "AI Agents";
} else if (isSlack) {
  topic = slackData.text
    || slackData.newsletter_content
       || slackData.message?.text
       || slackData.snippet
       || "AI Agents";
}

// Strip any slash-command prefix if coming from Slack
topic = topic.replace(/^\/(create-newsletter|newsletter)\s*/i, "").trim() || "AI Agents";

// ── Extract sender email ──────────────────────────────────────
// Gmail: "From" header contains "Name <email@domain.com>"
// Slack: user_profile.email or user.email
let senderEmail = "";
if (isGmail) {
  const rawFrom = gmailData.From || gmailData.from || "";
  // Parse "Display Name <email@example.com>" → email@example.com
  const match = rawFrom.match(/<([^>]+)>/) || rawFrom.match(/([^\s]+@[^\s]+)/);
  senderEmail = match ? match[1] : rawFrom;
} else if (isSlack) {
  senderEmail = slackData.user_profile?.email
             || slackData.event?.user_profile?.email
             || slackData.from_email
             || slackData.email
             || "";
}

// ── AI Agent output ───────────────────────────────────────────
const raw = $input.first().json.output || $input.first().json.text || "";

// ── 1. Parse OpenAI JSON response ────────────────────────────
let data;
try {
  data = JSON.parse(raw);
} catch (e) {
  const cleaned = raw.replace(/```json|```/g, "").trim();
  try {
    data = JSON.parse(cleaned);
  } catch (e2) {
    throw new Error(`Failed to parse AI response as JSON. Raw starts with: ${raw.slice(0, 120)}`);
  }
}

// ── 2. Helper utilities ───────────────────────────────────────
const today = new Date();
const dateStr = today.toLocaleDateString("en-US", {
  year: "numeric", month: "long", day: "numeric"
});
const year = today.getFullYear();

function estimateReadTime(text) {
  const words = (text || "").replace(/<[^>]+>/g, "").split(/\s+/).length;
  return Math.max(2, Math.round(words / 200));
}

function buildTags(tagsArr = []) {
  return (tagsArr || [])
    .slice(0, 5)
    .map(t => `<span class="tag">${t}</span>`)
    .join("\n");
}

function buildNumberedItems(itemsList = []) {
  return (itemsList || [])
    .slice(0, 5)
    .map((item, i) => `
      <div class="numbered-item">
        <div class="item-number">0${i + 1}</div>
        <div class="item-content">
          <div class="item-title">${item.title || ""}</div>
          <p class="item-desc">${item.description || ""}</p>
        </div>
      </div>
    `).join("");
}

// ── 3. Destructure AI response ────────────────────────────────
const {
  title = "AI Newsletter",
  intro = "",
  hero_stats = [],
  feature = {},
  quote = {},
  developments = [{}, {}, {}],
  list_section = {},
  tags = [],
  cta = {},
  footer = ""
} = data;

const s1 = hero_stats[0] || { value: "GPT-4o", label: "Model Used" };
const s2 = hero_stats[1] || { value: String(year), label: "Current Year" };
const s3 = hero_stats[2] || { value: "AI Agents", label: "Focus Area" };
const d1 = developments[0] || {};
const d2 = developments[1] || {};
const d3 = developments[2] || {};

const allText = [intro, feature.body || "", (list_section.items || []).map(i => i.description || "").join(" ")].join(" ");
const readTime = estimateReadTime(allText);

// Source label for footer
const sourceLabel = isGmail ? "Gmail" : "Slack";

// ── 4. Build HTML ─────────────────────────────────────────────
const htmlBody = `
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1.0"/>
<title>${title}</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;900&family=DM+Sans:wght@300;400;500;600&display=swap');
body{margin:0;padding:0;background:#0F0F12;font-family:'DM Sans',sans-serif;}
.email-wrapper{max-width:680px;margin:0 auto;background:#0F0F12;}
.header{background:#0A0A0E;border-bottom:1px solid #1E1E28;padding:32px 48px 28px;}
.header-top{display:flex;align-items:center;justify-content:space-between;margin-bottom:20px;}
.logo{font-family:'Playfair Display',serif;font-size:22px;font-weight:900;color:#E8E6FF;letter-spacing:-0.5px;}
.logo span{color:#7B6FFF;}
.issue-badge{background:#1A1A2E;border:1px solid #2E2E4E;border-radius:20px;padding:5px 14px;font-size:11px;font-weight:600;color:#9590C8;text-transform:uppercase;letter-spacing:1.2px;}
.header-divider{height:1px;background:linear-gradient(90deg,transparent,#2E2E4E 30%,#7B6FFF 50%,#2E2E4E 70%,transparent);margin:0;}
.header-meta{display:flex;align-items:center;gap:24px;margin-top:20px;}
.meta-item{font-size:12px;color:#5A5870;font-weight:500;}
.meta-item span{color:#9590C8;}
.hero{background:linear-gradient(135deg,#0D0B1E 0%,#0A0A0E 40%,#110B1E 100%);padding:56px 48px 48px;position:relative;overflow:hidden;}
.edition-tag{display:inline-flex;align-items:center;gap:8px;background:#1A1630;border:1px solid #2E2850;border-radius:4px;padding:6px 14px;margin-bottom:28px;}
.edition-tag span{font-size:11px;font-weight:600;color:#7B6FFF;text-transform:uppercase;letter-spacing:1.4px;}
.hero-title{font-family:'Playfair Display',serif;font-size:38px;font-weight:900;color:#F0EEFF;line-height:1.15;margin:0 0 20px;letter-spacing:-0.8px;}
.hero-intro{font-size:16px;color:#8A8799;line-height:1.75;max-width:520px;margin:0 0 32px;font-weight:300;}
.hero-stats{display:flex;gap:32px;}
.stat{border-left:2px solid #2E2850;padding-left:14px;}
.stat-value{font-size:22px;font-weight:600;color:#E8E6FF;font-family:'Playfair Display',serif;}
.stat-label{font-size:11px;color:#5A5870;text-transform:uppercase;letter-spacing:1px;font-weight:500;margin-top:2px;}
.section-label{display:flex;align-items:center;gap:12px;margin-bottom:20px;}
.section-label .line{flex:1;height:1px;background:#1E1E28;}
.section-label span{font-size:10px;font-weight:700;color:#5A5870;text-transform:uppercase;letter-spacing:2px;white-space:nowrap;}
.content{padding:0 48px;}
.feature-card{background:#13131C;border:1px solid #1E1E28;border-radius:12px;padding:36px;margin:32px 0;position:relative;overflow:hidden;}
.feature-card::before{content:'';position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,#7B6FFF,#63B3ED,#7B6FFF);}
.card-category{font-size:10px;font-weight:700;color:#7B6FFF;text-transform:uppercase;letter-spacing:2px;margin-bottom:16px;}
.card-title{font-family:'Playfair Display',serif;font-size:24px;font-weight:700;color:#F0EEFF;line-height:1.3;margin:0 0 16px;letter-spacing:-0.3px;}
.card-body{font-size:15px;color:#8A8799;line-height:1.8;margin:0 0 24px;font-weight:300;}
.card-body p{margin:0 0 14px;}
.card-body strong{color:#C5C1EF;font-weight:500;}
.tag-row{display:flex;flex-wrap:wrap;gap:8px;margin:20px 0;}
.tag{background:#1A1630;border:1px solid #2E2850;border-radius:20px;padding:5px 14px;font-size:12px;font-weight:500;color:#9590C8;}
.quote-block{background:#0D0B1E;border-left:3px solid #7B6FFF;border-radius:0 8px 8px 0;padding:24px 28px;margin:28px 0;}
.quote-text{font-family:'Playfair Display',serif;font-size:18px;font-style:italic;color:#C5C1EF;line-height:1.6;margin:0 0 12px;}
.quote-source{font-size:12px;color:#5A5870;font-weight:500;}
.three-grid{display:table;width:100%;border-collapse:separate;border-spacing:0;}
.grid-cell{display:table-cell;width:33.33%;vertical-align:top;padding:0 8px;}
.grid-cell:first-child{padding-left:0;}.grid-cell:last-child{padding-right:0;}
.mini-card{background:#13131C;border:1px solid #1E1E28;border-radius:10px;padding:24px 20px;}
.mini-card-icon{font-size:20px;margin-bottom:12px;}
.mini-card-title{font-size:14px;font-weight:600;color:#C5C1EF;margin:0 0 8px;line-height:1.3;}
.mini-card-body{font-size:13px;color:#6A677E;line-height:1.65;margin:0;font-weight:300;}
.numbered-section{margin:28px 0;}
.numbered-item{display:flex;gap:20px;padding:20px 0;border-bottom:1px solid #1A1A24;}
.numbered-item:last-child{border-bottom:none;}
.item-number{font-family:'Playfair Display',serif;font-size:32px;font-weight:900;color:#2E2850;line-height:1;min-width:36px;}
.item-title{font-size:15px;font-weight:600;color:#C5C1EF;margin:0 0 6px;}
.item-desc{font-size:13px;color:#6A677E;line-height:1.65;margin:0;font-weight:300;}
.cta-block{background:linear-gradient(135deg,#0D0B1E,#110B1E);border:1px solid #2E2850;border-radius:14px;padding:48px;text-align:center;margin:36px 0;}
.cta-title{font-family:'Playfair Display',serif;font-size:26px;font-weight:700;color:#F0EEFF;margin:0 0 14px;}
.cta-body{font-size:15px;color:#8A8799;line-height:1.7;max-width:420px;margin:0 auto 28px;}
.cta-btn{display:inline-block;background:#7B6FFF;border-radius:8px;padding:14px 36px;font-size:15px;font-weight:600;color:#ffffff;text-decoration:none;}
.footer-section{margin-top:8px;padding:36px 48px;border-top:1px solid #1A1A24;background:#0A0A0E;}
.footer-links{display:flex;gap:20px;justify-content:center;margin-bottom:20px;}
.footer-links a{font-size:12px;color:#5A5870;text-decoration:none;font-weight:500;}
.footer-text{font-size:11px;color:#3A3848;text-align:center;line-height:1.7;}
.footer-brand{font-family:'Playfair Display',serif;font-size:16px;color:#3A3848;text-align:center;margin-bottom:10px;}
.footer-brand span{color:#4A4560;}
.spacer-sm{height:24px;}.spacer-md{height:40px;}
</style>
</head>
<body>
<div class="email-wrapper">
  <div class="header">
    <div class="header-top">
      <div class="logo">The Agentic<span>.</span>Edge</div>
      <div class="issue-badge">Weekly Brief · ${dateStr}</div>
    </div>
    <div class="header-divider"></div>
    <div class="header-meta">
      <div class="meta-item">Topic: <span>${topic}</span></div>
      <div class="meta-item">Read time: <span>~${readTime} min</span></div>
      <div class="meta-item">Category: <span>AI Agents</span></div>
    </div>
  </div>

  <div class="hero">
    <div class="edition-tag"><span>Weekly Intelligence Brief</span></div>
    <h1 class="hero-title">${title}</h1>
    <p class="hero-intro">${intro}</p>
    <div class="hero-stats">
      <div class="stat"><div class="stat-value">${s1.value}</div><div class="stat-label">${s1.label}</div></div>
      <div class="stat"><div class="stat-value">${s2.value}</div><div class="stat-label">${s2.label}</div></div>
      <div class="stat"><div class="stat-value">${s3.value}</div><div class="stat-label">${s3.label}</div></div>
    </div>
  </div>

  <div class="content">
    <div class="spacer-md"></div>
    <div class="section-label"><div class="line"></div><span>Feature Deep Dive</span><div class="line"></div></div>

    <div class="feature-card">
      <div class="card-category">${feature.category || "AI Agents"}</div>
      <h2 class="card-title">${feature.title || ""}</h2>
      <div class="card-body">${feature.body || ""}</div>
      <div class="tag-row">${buildTags(tags)}</div>
    </div>

    <div class="quote-block">
      <p class="quote-text">${quote.text || ""}</p>
      <div class="quote-source">— ${quote.source || ""}</div>
    </div>

    <div class="section-label"><div class="line"></div><span>Key Developments</span><div class="line"></div></div>
    <div class="three-grid">
      <div class="grid-cell"><div class="mini-card">
        <div class="mini-card-icon">${d1.icon || "⚡"}</div>
        <div class="mini-card-title">${d1.title || ""}</div>
        <p class="mini-card-body">${d1.body || ""}</p>
      </div></div>
      <div class="grid-cell"><div class="mini-card">
        <div class="mini-card-icon">${d2.icon || "🔗"}</div>
        <div class="mini-card-title">${d2.title || ""}</div>
        <p class="mini-card-body">${d2.body || ""}</p>
      </div></div>
      <div class="grid-cell"><div class="mini-card">
        <div class="mini-card-icon">${d3.icon || "🧠"}</div>
        <div class="mini-card-title">${d3.title || ""}</div>
        <p class="mini-card-body">${d3.body || ""}</p>
      </div></div>
    </div>

    <div class="spacer-md"></div>
    <div class="section-label"><div class="line"></div><span>${list_section.title || "Top Insights"}</span><div class="line"></div></div>
    <div class="numbered-section">${buildNumberedItems(list_section.items)}</div>

    <div class="cta-block">
      <h3 class="cta-title">${cta.title || "Go Deeper"}</h3>
      <p class="cta-body">${cta.body || ""}</p>
      <a href="${cta.url || "#"}" class="cta-btn">${cta.button_text || "Explore Now"}</a>
    </div>
    <div class="spacer-sm"></div>
  </div>

  <div class="footer-section">
    <div class="footer-brand">The Agentic<span>.</span>Edge</div>
    <div class="footer-links">
      <a href="#">Unsubscribe</a>
      <a href="#">View in browser</a>
      <a href="#">Privacy Policy</a>
    </div>
    <p class="footer-text">
      ${footer || "This newsletter was generated by AI and curated for you."}<br/>
      Requested via ${sourceLabel}. © ${year} The Agentic Edge.
    </p>
  </div>
</div>
</body>
</html>
`;

// ── 5. Return to N8n ──────────────────────────────────────────
return [{
  json: {
    triggerSource: isGmail ? "gmail" : "slack",
    topic,
    senderEmail,
    htmlBody,
    emailSubject: `🤖 ${title} — The Agentic Edge`,
    toEmail: senderEmail,
  }
}];
